251	pub enum State {
252	    /// No active sort; the table is at rest.
253	    Idle,
254	}
255	
256	// ── Events ────────────────────────────────────────────────────────────────────
257	
258	/// Events for the Table.
259	#[derive(Clone, Debug, PartialEq)]
260	pub enum Event {
261	    /// Apply or toggle sort on the given column.
262	    SortColumn { column: String },
263	    /// Mark a row as selected.
264	    SelectRow(Key),
265	    /// Remove a row from the selection.
266	    DeselectRow(Key),
267	    /// Select all rows (uses `selection::Set::All`).
268	    SelectAll,
269	    /// Clear all selected rows.
270	    DeselectAll,
271	    /// Flip selection state of one row.
272	    ToggleRow(Key),
273	    /// Show the expanded content for a row.
274	    ExpandRow(Key),
275	    /// Hide the expanded content for a row.
276	    CollapseRow(Key),
277	    /// Move the logical grid focus to a cell.
278	    Focus { cell: (usize, usize) },
279	    /// Remove focus from the grid.
280	    Blur,
281	    /// Move the logical grid focus to a row.
282	    FocusRow(Key),
283	    /// Move the logical grid focus to a cell.
284	    FocusCell { row: Key, col: usize },
285	    /// Primary action triggered on a row (Enter key or double-click).
286	    RowAction(Key),
287	}
