289	/// Machine for the Table.
290	pub struct Machine;
291	
292	impl ars_core::Machine for Machine {
293	    type State   = State;
294	    type Event   = Event;
295	    type Context = Context;
296	    type Props   = Props;
297	    type Messages = Messages;
298	    type Api<'a> = Api<'a>;
299	
300	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
301	        let locale = env.locale.clone();
302	        let messages = messages.clone();
303	        let ids = ComponentIds::from_id(&props.id);
304	        let selection_state = selection::State::new(
305	            props.selection_mode,
306	            props.selection_behavior,
307	        );
308	        let ctx = Context {
309	            selected_rows: match &props.selected_rows {
310	                Some(v) => Bindable::controlled(v.clone()),
311	                None    => Bindable::uncontrolled(props.default_selected_rows.clone()),
312	            },
313	            selection_state,
314	            expanded_rows: match &props.expanded_rows {
315	                Some(v) => Bindable::controlled(v.clone()),
316	                None    => Bindable::uncontrolled(props.default_expanded_rows.clone()),
317	            },
318	            sort_descriptor: props.sort_descriptor.clone(),
319	            focused_cell: None,
320	            focused_row: None,
321	            focused_col: None,
322	            disabled_keys: props.disabled_keys.clone(),
323	            selection_mode: props.selection_mode,
324	            interactive: props.interactive,
325	            locale,
326	            messages,
327	            caption_id: ids.part("caption"),
328	            id: ids.id().to_string(),
329	        };
330	        (State::Idle, ctx)
331	    }
332	
333	    fn transition(
334	        state: &Self::State,
335	        event: &Self::Event,
336	        ctx:   &Self::Context,
337	        props: &Self::Props,
338	    ) -> Option<TransitionPlan<Self>> {
339	        match event {
340	            // ── Sort ─────────────────────────────────────────────────────────
341	            // Sort state lives entirely in `ctx.sort_descriptor` (see §1.1.1).
342	            // There is no State::Sorting variant — we stay in `Idle` throughout.
343	            Event::SortColumn { column } => {
344	                let new_direction = match ctx.sort_descriptor.get() {
345	                    Some(desc) if desc.column == *column => {
346	                        match desc.direction {
347	                            SortDirection::Ascending  => SortDirection::Descending,
348	                            SortDirection::Descending => SortDirection::None,
349	                            SortDirection::None       => SortDirection::Ascending,
350	                        }
351	                    }
352	                    // New column — always start ascending
353	                    _ => SortDirection::Ascending,
354	                };
355	                let col = column.clone();
356	                let dir = new_direction;
357	                Some(TransitionPlan::context_only(move |ctx| {
358	                    let descriptor = if dir == SortDirection::None {
359	                        None
360	                    } else {
361	                        Some(SortDescriptor { column: col, direction: dir })
362	                    };
363	                    ctx.sort_descriptor.set(descriptor);
364	                }))
365	                // Sort change notification is handled by the adapter layer.
366	            }
367	
368	            // ── Row Action ────────────────────────────────────────────────
369	            Event::RowAction(key) => {
370	                if ctx.disabled_keys.contains(key) { return None; }
371	                // RowAction is a notification event — the adapter fires the
372	                // on_row_action callback. No context mutation needed.
373	                Some(TransitionPlan::context_only(|_ctx| {}))
374	            }
375	
376	            // ── Row Selection (via selection::State from ars_collections) ────────
377	            Event::SelectRow(key) => {
378	                if ctx.selection_mode == selection::Mode::None { return None; }
379	                if ctx.disabled_keys.contains(key) { return None; }
380	                let key = key.clone();
381	                Some(TransitionPlan::context_only(move |ctx| {
382	                    let new_state = ctx.selection_state.select(key);
383	                    ctx.selected_rows.set(new_state.selected_keys.clone());
384	                    ctx.selection_state = new_state;
385	                }))
386	            }
387	
388	            Event::DeselectRow(key) => {
389	                if ctx.selection_mode == selection::Mode::None { return None; }
390	                if ctx.disabled_keys.contains(key) { return None; }
391	                let key = key.clone();
392	                Some(TransitionPlan::context_only(move |ctx| {
393	                    let new_state = ctx.selection_state.deselect(key);
394	                    ctx.selected_rows.set(new_state.selected_keys.clone());
395	                    ctx.selection_state = new_state;
396	                }))
397	            }
398	
399	            Event::ToggleRow(key) => {
400	                if ctx.selection_mode == selection::Mode::None { return None; }
401	                if ctx.disabled_keys.contains(key) { return None; }
402	                let key = key.clone();
403	                Some(TransitionPlan::context_only(move |ctx| {
404	                    let new_state = ctx.selection_state.toggle(key);
405	                    ctx.selected_rows.set(new_state.selected_keys.clone());
406	                    ctx.selection_state = new_state;
407	                }))
408	            }
409	
410	            Event::SelectAll => {
411	                if ctx.selection_mode != selection::Mode::Multiple { return None; }
412	                Some(TransitionPlan::context_only(|ctx| {
413	                    let new_state = ctx.selection_state.select_all();
414	                    ctx.selected_rows.set(new_state.selected_keys.clone());
415	                    ctx.selection_state = new_state;
416	                    // LiveAnnouncer: announce "All rows selected"
417	                }))
418	            }
419	
420	            Event::DeselectAll => {
421	                if ctx.selection_mode == selection::Mode::None { return None; }
422	                Some(TransitionPlan::context_only(|ctx| {
423	                    let new_state = ctx.selection_state.clear();
424	                    ctx.selected_rows.set(new_state.selected_keys.clone());
425	                    ctx.selection_state = new_state;
426	                }))
427	            }
428	
429	            // ── Row Expansion ─────────────────────────────────────────────────
430	            Event::ExpandRow(key) => {
431	                // Guard: skip when the row is already expanded — avoids
432	                // creating an unnecessary transition plan.
433	                if ctx.expanded_rows.get().contains(key) {
434	                    return None;
435	                }
436	                let key = key.clone();
437	                Some(TransitionPlan::context_only(move |ctx| {
438	                    let mut rows = ctx.expanded_rows.get().clone();
439	                    rows.insert(key);
440	                    ctx.expanded_rows.set(rows);
441	                }))
442	                // Expansion change notification is handled by the adapter layer.
443	            }
444	
445	            Event::CollapseRow(key) => {
446	                let key = key.clone();
447	                Some(TransitionPlan::context_only(move |ctx| {
448	                    let mut rows = ctx.expanded_rows.get().clone();
449	                    rows.remove(&key);
450	                    ctx.expanded_rows.set(rows);
451	                }))
452	                // Expansion change notification is handled by the adapter layer.
453	            }
454	
455	            // ── Grid Focus ────────────────────────────────────────────────────
456	            Event::Focus { cell } => {
457	                if !ctx.interactive { return None; }
458	                let c = *cell;
459	                Some(TransitionPlan::context_only(move |ctx| {
460	                    ctx.focused_cell = Some(c);
461	                }))
462	            }
463	
464	            Event::Blur => {
465	                Some(TransitionPlan::context_only(|ctx| {
466	                    ctx.focused_cell = None;
467	                }))
468	            }
469	
470	            Event::FocusRow(key) => {
471	                if !ctx.interactive { return None; }
472	                let key = key.clone();
473	                Some(TransitionPlan::context_only(move |ctx| {
474	                    ctx.focused_row = Some(key);
475	                }))
476	            }
477	
478	            Event::FocusCell { row, col } => {
479	                if !ctx.interactive { return None; }
480	                let r = row.clone();
481	                let c = *col;
482	                Some(TransitionPlan::context_only(move |ctx| {
483	                    ctx.focused_cell = Some((c, 0)); // row index resolved by adapter
484	                    ctx.focused_row = Some(r);
485	                    ctx.focused_col = Some(c);
486	                }))
487	            }
488	        }
489	    }
490	
491	    fn connect<'a>(
492	        state: &'a Self::State,
493	        ctx:   &'a Self::Context,
494	        props: &'a Self::Props,
495	        send:  &'a dyn Fn(Self::Event),
496	    ) -> Self::Api<'a> {
497	        Api { state, ctx, props, send }
498	    }
499	}

