725	    /// Handle keydown on a row element (used when `interactive=true`).
726	    pub fn on_row_keydown(&self, row_id: &Key, data: &KeyboardEventData, all_row_ids: &[&Key]) {
727	        let current_idx = all_row_ids.iter().position(|id| *id == row_id);
728	        match data.key {
729	            KeyboardKey::ArrowDown => {
730	                if let Some(idx) = current_idx {
731	                    if let Some(next) = all_row_ids.get(idx + 1) {
732	                        (self.send)(Event::FocusRow((*next).clone()));
733	                    }
734	                }
735	            }
736	            KeyboardKey::ArrowUp => {
737	                if let Some(idx) = current_idx {
738	                    if idx > 0 {
739	                        if let Some(prev) = all_row_ids.get(idx - 1) {
740	                            (self.send)(Event::FocusRow((*prev).clone()));
741	                        }
742	                    }
743	                }
744	            }
745	            KeyboardKey::Home => {
746	                if let Some(first) = all_row_ids.first() {
747	                    (self.send)(Event::FocusRow((*first).clone()));
748	                }
749	            }
750	            KeyboardKey::End => {
751	                if let Some(last) = all_row_ids.last() {
752	                    (self.send)(Event::FocusRow((*last).clone()));
753	                }
754	            }
755	            KeyboardKey::Enter | KeyboardKey::Space => {
756	                (self.send)(Event::ToggleRow(row_id.clone()));
757	            }
758	            _ => {}
759	        }
760	    }
