762	    /// Handle keydown on a cell element (used when `interactive=true` with grid role).
763	    ///
764	    /// RTL-aware: ArrowLeft/ArrowRight are resolved based on `ctx.dir` so that
765	    /// ArrowRight always moves toward the logical "end" column regardless of
766	    /// text direction.
767	    pub fn on_cell_keydown(&self, row_id: &Key, col: usize, data: &KeyboardEventData,
768	                           all_row_ids: &[&Key], col_count: usize) {
769	        // Resolve horizontal arrow keys for RTL.
770	        let is_rtl = self.ctx.dir == Direction::Rtl;
771	        let (next_col_key, prev_col_key) = if is_rtl {
772	            (KeyboardKey::ArrowLeft, KeyboardKey::ArrowRight)
773	        } else {
774	            (KeyboardKey::ArrowRight, KeyboardKey::ArrowLeft)
775	        };
776	
777	        match data.key {
778	            k if k == next_col_key => {
779	                if col + 1 < col_count {
780	                    (self.send)(Event::FocusCell { row: row_id.clone(), col: col + 1 });
781	                }
782	            }
783	            k if k == prev_col_key => {
784	                if col > 0 {
785	                    (self.send)(Event::FocusCell { row: row_id.clone(), col: col - 1 });
786	                }
787	            }
788	            KeyboardKey::ArrowDown => {
789	                let current_idx = all_row_ids.iter().position(|id| *id == row_id);
790	                if let Some(idx) = current_idx {
791	                    if let Some(next) = all_row_ids.get(idx + 1) {
792	                        (self.send)(Event::FocusCell { row: (*next).clone(), col });
793	                    }
794	                }
795	            }
796	            KeyboardKey::ArrowUp => {
797	                let current_idx = all_row_ids.iter().position(|id| *id == row_id);
798	                if let Some(idx) = current_idx {
799	                    if idx > 0 {
800	                        if let Some(prev) = all_row_ids.get(idx - 1) {
801	                            (self.send)(Event::FocusCell { row: (*prev).clone(), col });
802	                        }
803	                    }
804	                }
805	            }
806	            KeyboardKey::Home => {
807	                (self.send)(Event::FocusCell { row: row_id.clone(), col: 0 });
808	            }
809	            KeyboardKey::End => {
810	                (self.send)(Event::FocusCell { row: row_id.clone(), col: col_count.saturating_sub(1) });
811	            }
812	            _ => {}
813	        }
814	    }
