798	
799	impl ars_core::Machine for Machine {
800	    type State = State;
801	    type Event = Event;
802	    type Context = Context;
803	    type Props = Props;
804	    type Messages = Messages;
805	    type Effect = Effect;
806	    type Api<'a> = Api<'a>;
807	
808	    fn init(
809	        props: &Self::Props,
810	        env: &Env,
811	        messages: &Self::Messages,
812	    ) -> (Self::State, Self::Context) {
