/// Controls behavior when Escape is pressed while rows are selected.
#[derive(Clone, Debug, PartialEq)]
pub enum EscapeKeyBehavior {
    /// Escape clears the current selection.
    ClearSelection,
    /// Escape is not handled by the Table.
    None,
