    /// Returns the number of selected items, or `None` for `All`.
    #[must_use]
    pub fn count(&self) -> Option<usize> {
        match self {
            Self::Empty => Some(0),
            Self::Single(_) => Some(1),
            Self::Multiple(keys) => Some(keys.len()),
            Self::All => None,
