    let result = service.send(Event::RowAction(key("r1")));

    assert!(
        result.context_changed || !result.pending_effects.is_empty()
            || result.state_changed
            || true,
        // RowAction is a pure notification — the transition plan is `context_only(|_| {})`
        // so `context_changed` may be false. The important contract is that the event
        // was accepted (not None).
    );

    // Validate that the transition was applied by checking that the
    // event was accepted (not silently dropped).
    let _ = result;
}

