1	//! Inline unit + snapshot tests for the [`Table`](super) state machine.
2	//!
3	//! Tests are organized by topic, mirroring the issue's "Tests to add
4	//! first" checklist (#286) and covering the §5 SelectAll, §6 Column
5	//! Resizing, and §3.5 Virtual Scrolling variants.
6	
7	use alloc::{
8	    collections::BTreeSet,
9	    string::{String, ToString as _},
10	    vec,
11	    vec::Vec,
12	};
13	use core::cell::RefCell;
14	
15	use ars_collections::{Key, SortDescriptor, SortDirection, selection};
16	use ars_core::{AriaAttr, AttrMap, Env, HtmlAttr, MessageFn, Service};
17	use ars_interactions::{KeyboardEventData, KeyboardKey};
18	use insta::assert_snapshot;
19	
20	use super::*;
21	
22	// ── Test fixtures ────────────────────────────────────────────────────
23	
24	/// Builds a `Key::String` from a `&str`.
25	fn key(value: &str) -> Key {
26	    Key::str(value)
27	}
28	
29	/// Builds a baseline keyboard event with the given normalized key and no
30	/// modifiers held.
31	fn keydown(k: KeyboardKey) -> KeyboardEventData {
32	    KeyboardEventData {
33	        key: k,
34	        character: None,
35	        code: String::new(),
36	        shift_key: false,
37	        ctrl_key: false,
38	        alt_key: false,
39	        meta_key: false,
40	        repeat: false,
41	        is_composing: false,
42	    }
43	}
44	
45	/// Builds a Ctrl-modified keyboard event.
46	fn ctrl_keydown(k: KeyboardKey) -> KeyboardEventData {
47	    let mut data = keydown(k);
48	    data.ctrl_key = true;
49	    data
50	}
51	
52	/// Returns baseline test props with a stable component id.
53	fn test_props() -> Props {
54	    Props {
55	        id: "table".to_string(),
56	        ..Props::default()
57	    }
58	}
59	
60	/// Returns test props in multi-selection mode.
61	fn test_props_multi() -> Props {
62	    Props {
63	        id: "table".to_string(),
64	        selection_mode: selection::Mode::Multiple,
65	        ..Props::default()
66	    }
67	}
68	
69	/// Returns test props in single-selection mode.
70	fn test_props_single() -> Props {
71	    Props {
72	        id: "table".to_string(),
73	        selection_mode: selection::Mode::Single,
74	        ..Props::default()
75	    }
76	}
77	
78	/// Builds a service with the supplied props and registers `rows` so
79	/// selection / expansion pruning has data to work against.
80	fn service_with_rows(props: Props, rows: &[Key]) -> Service<Machine> {
81	    let mut service = Service::<Machine>::new(props, &Env::default(), &Messages::default());
82	    drop(service.send(Event::SetRows(rows.to_vec())));
83	    service
84	}
85	
86	/// Records every event dispatched through the connected `send` closure.
87	type EventRecorder = RefCell<Vec<Event>>;
88	
89	/// Pushes the captured event into the supplied recorder.
90	fn record(recorder: &EventRecorder, event: Event) {
91	    recorder.borrow_mut().push(event);
92	}
93	
94	/// Snapshot the `AttrMap` debug representation.
95	fn snapshot_attrs(attrs: &AttrMap) -> String {
96	    format!("{attrs:#?}")
97	}
