103	#[test]
104	fn table_root_produces_table_role() {
105	    let service = service_with_rows(test_props(), &[]);
106	
107	    let attrs = service.connect(&|_| {}).table_attrs();
108	
109	    assert_eq!(
110	        attrs.get(&HtmlAttr::Role).map(|v| v.to_string()),
111	        Some("table".to_string())
