fn would_empty_after_deselect(set: &selection::Set, key: &Key) -> bool {
    match set {
        selection::Set::Empty => false,
        selection::Set::Single(k) => k == key,
        selection::Set::Multiple(keys) => keys.len() == 1 && keys.contains(key),
